load('exp2_lab2_v2.mat')

% Voltage across Diode-Connected Transistor vs Input Voltage (all three)
figure(); %[output:45b0e874]
axis equal %[output:45b0e874]
plot(V_in_120, V_q_120, '.', DisplayName='120 \Omega') %[output:45b0e874]
hold on; %[output:45b0e874]
plot(V_in_10k, V_q_10k, '.', DisplayName='10 k\Omega') %[output:45b0e874]
plot(V_in_200k, V_q_200k, '.', DisplayName='200 k\Omega') %[output:45b0e874]

fit_vals = polyfit(V_in_120(find(V_in_120 < 0.6)), V_q_120(find(V_in_120 < 0.6)), 1);
plot(linspace(0, 0.7, 101), fit_vals(1) .* linspace(0, 0.7, 101) + fit_vals(2), DisplayName=['Transistor-Dominant Regime Voltage Fit, R = 120 \Omega: y = (', num2str(fit_vals(1), 3), ' V/V)x + ', num2str(fit_vals(2), 3), ' V']) %[output:45b0e874]

fit_vals = polyfit(V_in_10k(find(V_in_10k < 0.5)), V_q_10k(find(V_in_10k < 0.5)), 1);
plot(linspace(0, 0.7, 101), fit_vals(1) .* linspace(0, 0.7, 101) + fit_vals(2), DisplayName=['Transistor-Dominant Regime Voltage Fit, R = 10 k\Omega: y = (', num2str(fit_vals(1), 3), ' V/V)x + ', num2str(fit_vals(2), 3), ' V']) %[output:45b0e874]

fit_vals = polyfit(V_in_200k(find(V_in_200k < 0.4)), V_q_200k(find(V_in_200k < 0.4)), 1);
plot(linspace(0, 0.7, 101), fit_vals(1) .* linspace(0, 0.7, 101) + fit_vals(2), DisplayName=['Transistor-Dominant Regime Voltage Fit, R = 200 k\Omega: y = (', num2str(fit_vals(1), 3), ' V/V)x + ', num2str(fit_vals(2), 3), ' V']) %[output:45b0e874]

title('Voltage Across Transistor vs. Input Voltage') %[output:45b0e874]
xlabel('V_{in} (V)') %[output:45b0e874]
ylabel('V_{Q} (V)') %[output:45b0e874]
lgd = legend(); %[output:45b0e874]
lgd.Box = 'off'; %[output:45b0e874]
lgd.Location = 'southoutside'; %[output:45b0e874]
grid on %[output:45b0e874]

% Current Flowing into Circuit vs. Input Voltage
figure(); %[output:0136588e]
semilogy(V_in_120, I_in_120, '.', DisplayName='120 \Omega') %[output:0136588e]
hold on; %[output:0136588e]
semilogy(V_in_10k, I_in_10k, '.', DisplayName='10 k\Omega') %[output:0136588e]
semilogy(V_in_200k, I_in_200k, '.', DisplayName='200 k\Omega') %[output:0136588e]

fit_vals = fit(V_in_120(find(V_in_120 > 1))', I_in_120(find(V_in_120 > 1))', 'exp2'); %[output:03501a2d]
semilogy(linspace(0, 3, 101), fit_vals.a .* exp(linspace(0, 3, 101) .* fit_vals.b) + fit_vals.c .* exp(linspace(0, 3, 101) .* fit_vals.d), DisplayName=['Effect of Transistor Fitted Line, R = 120 \Omega: y = ', num2str(fit_vals.a, 3), 'x ', char(8487), ' + ', num2str(fit_vals.b), ' V']) %[output:0136588e]
fit_vals = fit(V_in_10k(find(V_in_10k > 1))', I_in_10k(find(V_in_10k > 1))', 'exp2');
semilogy(linspace(0, 3, 101), fit_vals.a .* exp(linspace(0, 3, 101) .* fit_vals.b) + fit_vals.c .* exp(linspace(0, 3, 101) .* fit_vals.d), DisplayName=['Effect of Transistor Fitted Line, R = 10 k\Omega: y = ', num2str(fit_vals.a, 3), 'x ', char(8487), ' + ', num2str(fit_vals.b), ' V']) %[output:0136588e]
fit_vals = fit(V_in_200k(find(V_in_200k > 1))', I_in_200k(find(V_in_200k > 1))', 'exp2');
semilogy(linspace(0, 3, 101), fit_vals.a .* exp(linspace(0, 3, 101) .* fit_vals.b) + fit_vals.c .* exp(linspace(0, 3, 101) .* fit_vals.d), DisplayName=['Effect of Transistor Fitted Line, R = 200 k\Omega: y = ', num2str(fit_vals.a, 3), 'x ', char(8487), ' + ', num2str(fit_vals.b), ' V']) %[output:0136588e]

title('Current vs. Input Voltage of Circuit') %[output:0136588e]
xlabel('V_{in} (V)') %[output:0136588e]
ylabel('I_{in} (A)') %[output:0136588e]
ylim([10e-9 10e-2]) %[output:0136588e]
lgd = legend(Location="southoutside"); %[output:0136588e]
lgd.Box = 'off'; %[output:0136588e]

% Plot showing input current vs applied input voltage (3 plots)
U_T = 0.0191; % V; From Experiment 1 Data
I_s = 3e-15; % A

figure(); %[output:8a330d95]
hold on; %[output:8a330d95]
plot(V_in_120, I_in_120, '.', DisplayName='Measured Data') %[output:8a330d95]
plot(log(((U_T/120)/I_s) + 1) * U_T, U_T/120, 'x', DisplayName=['(V_{on} = ', num2str(log(((U_T/120)/I_s) + 1) * U_T, 3), ' V, I_{on} = ', num2str(U_T/120, 3),' A) with U_{T} = 25 mV; I_{s} = 3 fA']) %[output:8a330d95]

fit_vals = polyfit(V_in_120(find(V_in_120 < 0.6)), I_in_120(find(V_in_120 < 0.6)), 1);
plot(linspace(0, 3, 101), fit_vals(1) .* linspace(0, 3, 101) + fit_vals(2), DisplayName=['\deltaV Transistor Dominance Fit: y = (', num2str(fit_vals(1), 3), ' ', char(8487), ')x + ', num2str(fit_vals(2), 3), ' A']) %[output:8a330d95]

fit_vals = polyfit(V_in_120(find(0.6 < V_in_120 & V_in_120 < 1.1)), I_in_120(find(0.6 < V_in_120 & V_in_120 < 1.1)), 1);
plot(linspace(0.5, 1.5, 101), fit_vals(1) .* linspace(0.5, 1.5, 101) + fit_vals(2), DisplayName=['\deltaV Resistor Dominance Fit: y = (', num2str(fit_vals(1), 3), ' ', char(8487), ')x + ', num2str(fit_vals(2), 3), ' A']) %[output:8a330d95]

title('Circuit with 120 \Omega Resistor IV Plot') %[output:8a330d95]
xlabel('V_{in} (V)') %[output:8a330d95]
ylabel('I_{in} (A)') %[output:8a330d95]
legend(Location='southoutside') %[output:8a330d95]

